// Get brand config and determine KDP book type
const product = $input.first().json;
const category = (product.Category || product.KDP_Type || '').toLowerCase();

// Map to KDP book types
let bookType = 'ebook';
if (category.includes('planner') || category.includes('journal') || category.includes('notebook') || category.includes('low content')) bookType = 'low_content';
else if (category.includes('coloring') || category.includes('color') || category.includes('ai art')) bookType = 'coloring';
else if (category.includes('activity') || category.includes('education') || category.includes('learning')) bookType = 'activity';
else if (category.includes('puzzle') || category.includes('word search') || category.includes('crossword')) bookType = 'puzzle';
else if (category.includes('ebook') || category.includes('guide') || category.includes('business') || category.includes('productivity')) bookType = 'ebook';

// KDP trim sizes by book type
const trimSizes = {
  ebook: { width: null, height: null, format: 'EPUB+PDF', kindle: true },
  low_content: { width: 8.5, height: 11, format: 'PDF_ONLY', kindle: false, pages: 120 },
  coloring: { width: 8.5, height: 11, format: 'PDF_ONLY', kindle: false, pages: 40 },
  activity: { width: 8.5, height: 8.5, format: 'PDF_ONLY', kindle: false, pages: 60 },
  puzzle: { width: 8.5, height: 11, format: 'PDF_ONLY', kindle: false, pages: 80 }
};

// KDP pricing by type
const kdpPricing = {
  ebook: { min: 2.99, max: 9.99, sweet_spot: 4.99, royalty_rate: 0.70 },
  low_content: { min: 5.99, max: 14.99, sweet_spot: 8.99, royalty_rate: 0.60 },
  coloring: { min: 6.99, max: 16.99, sweet_spot: 9.99, royalty_rate: 0.60 },
  activity: { min: 5.99, max: 14.99, sweet_spot: 8.99, royalty_rate: 0.60 },
  puzzle: { min: 6.99, max: 16.99, sweet_spot: 9.99, royalty_rate: 0.60 }
};

return [{ json: {
  ...product,
  book_type: bookType,
  trim_size: trimSizes[bookType],
  kdp_pricing: kdpPricing[bookType],
  product_id: (product.Product_Name || 'book').toLowerCase().replace(/[^a-z0-9]/g, '_') + '_' + Date.now(),
  _stage: 'book_type_detected'
}}];

