// Universal parser for all 5 book types
const raw = $input.first().json;
const productData = $('⚙️ Detect KDP Book Type + Specs').first().json;

let bookData;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  bookData = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  bookData = { error: true, message: e.message, raw: raw?.message?.content?.substring(0,300) };
}

const productId = productData.product_id;
const bookType = productData.book_type;

// Determine which pages to render
let pagesArray = [];
if (bookType === 'ebook') {
  // Build pages from chapters
  const chapters = bookData.book_content?.chapters || [];
  pagesArray = chapters.map((ch, i) => ({
    type: 'chapter',
    number: i + 1,
    title: ch.title,
    content: ch.content,
    action_steps: ch.action_steps || []
  }));
} else if (bookType === 'low_content') {
  pagesArray = bookData.pages || [];
} else if (bookType === 'coloring') {
  pagesArray = bookData.coloring_pages || [];
} else if (bookType === 'activity') {
  pagesArray = bookData.activity_pages || [];
} else if (bookType === 'puzzle') {
  pagesArray = bookData.puzzles || [];
}

return [{ json: {
  book_data: bookData,
  book_type: bookType,
  product_id: productId,
  metadata: bookData.book_metadata || {},
  pages_array: pagesArray,
  pages_count: pagesArray.length,
  cover_brief: bookData.cover_brief || {},
  product_source: productData,
  _parsed: true,
  _parsed_at: new Date().toISOString()
}}];

// Build complete book HTML based on type
const input = $input.first().json;
const bookType = input.book_type;
const meta = input.metadata;
const pages = input.pages_array;
const bookData = input.book_data;

// Brand colors
const PRIMARY = '#1B2A4A';
const ACCENT = '#C9A84C';
const BG = '#FFFFFF';
const TEXT = '#2D3748';

// Base CSS for all book types
const baseCSS = `
  @page { margin: 0; size: 8.5in 11in; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Arial', sans-serif; color: ${TEXT}; background: ${BG}; }
  .page { width: 8.5in; min-height: 11in; padding: 0.75in 0.875in 0.75in 0.5in; page-break-after: always; position: relative; }
  .page-number { position: absolute; bottom: 0.4in; left: 50%; transform: translateX(-50%); font-size: 10pt; color: #999; }
  h1 { font-size: 28pt; color: ${PRIMARY}; margin-bottom: 20px; }
  h2 { font-size: 20pt; color: ${PRIMARY}; margin-bottom: 16px; }
  h3 { font-size: 14pt; color: ${ACCENT}; margin-bottom: 12px; }
  p { font-size: 11pt; line-height: 1.7; margin-bottom: 14px; }
  .accent-bar { width: 60px; height: 4px; background: ${ACCENT}; margin-bottom: 20px; }
  @media print { * { -webkit-print-color-adjust: exact; print-color-adjust: exact; } }
`;

let fullHTML = '';

if (bookType === 'ebook' || bookType === 'low_content') {
  // ── EBOOK: Full styled manuscript ─────────────────────
  const frontMatter = bookData.book_content?.front_matter || {};
  const chapters = bookData.book_content?.chapters || [];

  const chaptersHTML = chapters.map(ch => `
    <div class="page">
      <div class="chapter-label">Chapter ${ch.number}</div>
      <h2>${ch.title}</h2>
      <div class="accent-bar"></div>
      ${ch.content.split('\n').filter(p=>p.trim()).map(p=>`<p>${p}</p>`).join('')}
      ${ch.action_steps?.length ? `
        <div class="action-box">
          <h3>Action Steps</h3>
          <ul>${ch.action_steps.map(s=>`<li>${s}</li>`).join('')}</ul>
        </div>` : ''}
      <div class="page-number">${ch.number + 3}</div>
    </div>
  `).join('');

  fullHTML = `<!DOCTYPE html><html><head><meta charset="UTF-8">
  <style>
    ${baseCSS}
    .cover-page { background: linear-gradient(135deg, ${PRIMARY}, #2D4A7A); color: white; display: flex; flex-direction: column; justify-content: center; padding: 1.5in; }
    .cover-page h1 { color: white; font-size: 36pt; }
    .cover-subtitle { font-size: 16pt; color: rgba(255,255,255,0.85); margin-top: 16px; }
    .cover-author { margin-top: 60px; color: ${ACCENT}; font-size: 14pt; }
    .toc-page { }
    .toc-item { padding: 10px 0; border-bottom: 1px solid #eee; font-size: 12pt; display: flex; justify-content: space-between; }
    .chapter-label { font-size: 9pt; text-transform: uppercase; letter-spacing: 3px; color: ${ACCENT}; margin-bottom: 8px; }
    .action-box { background: #F0F4FF; border-left: 4px solid ${ACCENT}; padding: 20px 24px; margin-top: 30px; border-radius: 0 8px 8px 0; }
    .action-box ul li { padding: 6px 0; font-size: 10.5pt; }
  </style>
  </head><body>
  <div class="page cover-page">
    <h1>${meta.title}</h1>
    <div class="cover-subtitle">${meta.subtitle || ''}</div>
    <div class="cover-author">${meta.author_name}</div>
  </div>
  <div class="page">
    <h2>Table of Contents</h2><div class="accent-bar"></div>
    ${(meta.kdp_categories || []).map((c,i) => `<div class="toc-item"><span>Chapter ${i+1}</span><span>${i+4}</span></div>`).join('')}
  </div>
  <div class="page">
    <h2>Introduction</h2><div class="accent-bar"></div>
    ${(bookData.book_content?.introduction || '').split('\n').filter(p=>p.trim()).map(p=>`<p>${p}</p>`).join('')}
  </div>
  ${chaptersHTML}
  <div class="page">
    <h2>Conclusion</h2><div class="accent-bar"></div>
    ${(bookData.book_content?.conclusion || '').split('\n').filter(p=>p.trim()).map(p=>`<p>${p}</p>`).join('')}
  </div>
  <div class="page">
    <h2>About the Author</h2><div class="accent-bar"></div>
    <p>${bookData.book_content?.about_author || ''}</p>
  </div>
  </body></html>`;

} else if (bookType === 'low_content') {
  // ── LOW CONTENT: Planner/Journal pages ───────────────
  const pagesHTML = pages.map((page, i) => 
    page.html_template ? 
    `<div class="page">${page.html_template}<div class="page-number">${i+3}</div></div>` :
    `<div class="page"><div class="page-number">${i+3}</div></div>`
  ).join('');

  fullHTML = `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>${baseCSS}</style></head><body>
  <div class="page" style="display:flex;flex-direction:column;justify-content:center;align-items:center;background:${PRIMARY};">
    <h1 style="color:white;text-align:center;">${meta.title}</h1>
  </div>
  ${pagesHTML}</body></html>`;

} else if (bookType === 'coloring') {
  // ── COLORING: Placeholder pages with SD prompts ───────
  // Actual images generated separately via Replicate
  const colorPagesHTML = pages.map((page, i) => `
    <div class="page" style="display:flex;flex-direction:column;align-items:center;justify-content:center;">
      <div style="width:7.5in;height:9in;border:1px solid #eee;display:flex;align-items:center;justify-content:center;background:#fafafa;">
        <p style="color:#ccc;font-size:10pt;">[Coloring Page ${i+1}: ${page.theme}]</p>
      </div>
      ${page.title_text ? `<p style="margin-top:8px;font-size:10pt;color:#666;">${page.title_text}</p>` : ''}
    </div>
    <div class="page"></div>
  `).join('');

  fullHTML = `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>${baseCSS}</style></head><body>
  <div class="page" style="display:flex;flex-direction:column;justify-content:center;align-items:center;background:${PRIMARY};">
    <h1 style="color:white;text-align:center;">${meta.title}</h1>
    <p style="color:${ACCENT};margin-top:20px;">A Coloring Book by ${meta.author_name}</p>
  </div>
  ${colorPagesHTML}</body></html>`;

} else {
  // ── ACTIVITY / PUZZLE: Use HTML from each page ────────
  const actPagesHTML = pages.map((page, i) => 
    `<div class="page">${page.html_content || page.answer_html || `<h3>${page.theme || page.topic || 'Page ' + (i+1)}</h3>`}<div class="page-number">${i+3}</div></div>`
  ).join('');

  fullHTML = `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>${baseCSS}</style></head><body>
  <div class="page" style="display:flex;flex-direction:column;justify-content:center;align-items:center;background:${PRIMARY};">
    <h1 style="color:white;text-align:center;">${meta.title}</h1>
  </div>
  ${actPagesHTML}</body></html>`;
}

return [{ json: {
  ...input,
  html_content: fullHTML,
  html_path: `/tmp/kdp_${input.product_id}_interior.html`,
  pdf_path: `/tmp/kdp_${input.product_id}_interior.pdf`,
  epub_path: `/tmp/kdp_${input.product_id}.epub`,
  _html_built: true
}}];

