// Assemble complete KDP package record
const pdfResult = $('💻 Render KDP Interior PDF').first().json;
const epubResult = $('📱 Build EPUB (Kindle Format)').first().json;
const coverImage = $('🔍 Poll Cover Result').first().json;
const bookInput = $('🖥️ Build KDP-Formatted HTML').first().json;

// Parse PDF result
const pdfOutput = pdfResult?.stdout || '';
const pdfSuccess = pdfOutput.includes('SUCCESS');
const pdfPath = pdfSuccess ? pdfOutput.split('|')[1] : null;
const pdfSize = pdfSuccess ? pdfOutput.split('|')[2] : null;

// Parse EPUB result  
const epubOutput = epubResult?.stdout || '';
const epubSuccess = epubOutput.includes('EPUB_SUCCESS');
const epubPath = epubSuccess ? epubOutput.split('|')[1] : null;

// Cover image URL from Replicate
const coverUrl = coverImage?.output?.[0] || null;

const kdpPackage = {
  product_id: bookInput.product_id,
  book_type: bookInput.book_type,
  metadata: bookInput.metadata,

  files: {
    interior_pdf: pdfPath,
    interior_pdf_size: pdfSize,
    epub_file: epubPath,
    cover_image_url: coverUrl,
    cover_html_path: `/tmp/kdp_${bookInput.product_id}_cover.html`
  },

  kdp_upload_data: {
    title: bookInput.metadata.title,
    subtitle: bookInput.metadata.subtitle,
    author: bookInput.metadata.author_name,
    description_html: bookInput.metadata.book_description_html,
    keywords: bookInput.metadata.kindle_keywords,
    categories: bookInput.metadata.kdp_categories,
    price_usd: bookInput.metadata.price_usd,
    page_count: bookInput.metadata.page_count,
    language: 'English',
    publication_date: new Date().getFullYear().toString(),
    enrollment_kdp_select: bookInput.metadata.enrollment_kdp_select || false
  },

  status: {
    pdf_ready: pdfSuccess,
    epub_ready: epubSuccess,
    cover_ready: !!coverUrl,
    ready_for_upload: pdfSuccess && !!coverUrl
  },

  assembled_at: new Date().toISOString()
};

return [{ json: kdpPackage }];
